package schema

import "strings"

// CodeObjectOptions controls option-aware rendering and validation for owned
// code objects (ViewDef, ProcedureDef). The zero value preserves the default
// no-decoration behavior so existing callers see no change unless they
// explicitly pass a populated CodeObjectOptions to the *WithOptions helpers.
//
// Apply-owned decoration: both OwnershipNotice and DocPreamble are
// apply-owned, not declaration-owned. They are injected into the live SQL
// only by Apply*WithOptions and are tolerated (but not required) by
// Validate*WithOptions. Validate-only callers may pass options without
// forcing the markers to exist in the live database.
//
// For per-object documentation carried on the declaration itself, use
// ViewDef.WithDocAnnotation / ProcedureDef.WithDocAnnotation instead. That
// annotation renders last among the leading comments — after DocPreamble,
// closest to the SQL payload. Validation ignores leading block-comment front
// matter, so comment-only changes do not participate in drift comparison.
//
// Intended usage is one central config built once in bootstrap and passed
// to ApplyViewsWithOptions / ValidateViewsWithOptions /
// ApplyProceduresWithOptions / ValidateProceduresWithOptions rather than
// repeated per-definition boilerplate:
//
//	opts := schema.CodeObjectOptions{
//	    OwnershipNotice: schema.DefaultOwnershipNotice,
//	    DocPreamble:     "Generated by bootstrap. See docs/schema.md.",
//	}
//	if err := schema.ApplyViewsWithOptions(ctx, db, d, opts, views...); err != nil {
//	    return err
//	}
//	if err := schema.ValidateViewsWithOptions(ctx, db, d, opts, views...); err != nil {
//	    return err
//	}
//
// Render order when fields are set: OwnershipNotice first (chuck-owned marker
// up top so DB readers see it immediately), then DocPreamble, then any
// per-object doc annotation, then payload. Each non-empty segment is rendered
// as its own `/* ... */` SQL block comment; comment blocks are separated by a
// blank line and the payload starts on the next line after the final block.
// Validate*WithOptions strips this exact ordered prefix from the live text
// before canonical comparison, then ignores any remaining leading
// block-comment front matter on both sides; comment-only changes therefore do
// not report drift.
type CodeObjectOptions struct {
	// OwnershipNotice is an opt-in apply-owned marker the option-aware Apply*
	// helpers prepend to the rendered view body or procedure definition as a
	// SQL block comment. When empty (the default) nothing is emitted.
	//
	// Validate*WithOptions tolerates absence of the marker in live text:
	// stripping is best-effort, and live objects applied by bare helpers (or
	// out-of-band with no notice) still validate cleanly against the same
	// declared body. Validation ignores leading block-comment front matter
	// entirely, so different leading comments — including a stale notice
	// that no longer matches the configured value — do not by themselves
	// report drift.
	//
	// Engine notes:
	//   - SQLite: comment survives in sqlite_master.sql.
	//   - MSSQL:  comment survives in sys.sql_modules.definition.
	//   - Postgres: pg_get_viewdef discards comments when it reconstructs the
	//     SELECT, so the notice will land in the live CREATE statement but
	//     will not be visible when an operator reads pg_get_viewdef output.
	//     This does not produce false drift because Postgres view validation
	//     is existence-only (see ErrViewBodyComparisonUnsupported).
	OwnershipNotice string

	// DocPreamble is an optional caller-controlled doc comment the
	// option-aware Apply* helpers prepend to the rendered view body or
	// procedure definition as a SQL block comment. Rendered before
	// OwnershipNotice when both are set. Intended for caller commentary
	// (purpose, contact, link to runbook) and is not treated as proof of
	// ownership — it is metadata only.
	//
	// Validate*WithOptions strips the exact configured DocPreamble from live
	// text alongside OwnershipNotice. Validation then ignores any remaining
	// leading block-comment front matter, so absent or different leading
	// comments follow the same comment-insensitive rules as OwnershipNotice.
	DocPreamble string

	// Metadata opts the option-aware apply path into recording an entry in
	// chuck's snapshot operational metadata ledger after each successful
	// view / procedure apply. When nil (the zero value) no ledger row is
	// written and the apply path behaves identically to bare apply.
	//
	// Callers must run EnsureMetadataTables once before the first opt-in
	// apply; the ledger writes assume the tables exist. The ledger is
	// strictly apply-side in this first pass — Validate*WithOptions
	// ignores Metadata entirely and does not compare definition hashes.
	//
	// Owner is required when Metadata is non-nil; an empty Owner surfaces
	// as ErrMetadataOwnerMissing rather than recording an ambiguous row.
	Metadata *MetadataConfig
}

// DefaultOwnershipNotice is the canonical chuck-owned ownership notice text
// suggested by issue #84. Deliberately soft: it says out-of-band changes
// "may" fail validation or be overwritten because the explicit Validate* /
// Apply* lanes leave that choice to the caller, and Postgres view validation
// is existence-only today (see ErrViewBodyComparisonUnsupported), so a
// stronger promise would be dishonest. The notice embeds the chuck GitHub
// URL rather than the bare project name so DB readers who do not know what
// "chuck" is can find the project directly.
const DefaultOwnershipNotice = "Owned by https://github.com/catgoose/chuck. Do not edit in database.\n" +
	"Out-of-band changes may fail validation or be overwritten by apply/bootstrap."

// renderOwnershipComment formats a notice as a SQL block comment, or returns
// "" when no notice is set. Engine-agnostic `/* ... */` syntax is accepted by
// SQLite, MSSQL, and Postgres at the body / definition payload positions where
// chuck injects it.
func renderOwnershipComment(notice string) string {
	if notice == "" {
		return ""
	}
	return "/* " + notice + " */"
}

// renderApplyPrefix returns the full configured comment prefix that
// Apply*WithOptions prepends to the rendered body / definition payload.
// Render order: OwnershipNotice (apply-owned, chuck-owned marker up top),
// DocPreamble (apply-owned), declared per-object annotation (closest to the
// payload). Each non-empty segment becomes its own `/* ... */` block
// comment. Comment blocks are separated by a blank line, and the returned
// prefix ends with a single newline so the payload starts on the next line.
// When all three are empty, returns "".
func renderApplyPrefix(opts CodeObjectOptions, declaredAnnotation string) string {
	var comments []string
	if c := renderOwnershipComment(opts.OwnershipNotice); c != "" {
		comments = append(comments, c)
	}
	if c := renderOwnershipComment(opts.DocPreamble); c != "" {
		comments = append(comments, c)
	}
	if c := renderOwnershipComment(declaredAnnotation); c != "" {
		comments = append(comments, c)
	}
	if len(comments) == 0 {
		return ""
	}
	return "\n" + strings.Join(comments, "\n\n") + "\n"
}

// applyOwnershipNoticePrefix returns the body or definition payload prefixed
// with the rendered apply-comment prefix when one is set, otherwise the
// payload unchanged. Comments render one-per-line with a blank line between
// blocks so DB readers can scan stacked annotations more easily, regardless
// of whether the payload starts with a SELECT keyword (views), a parameter
// declaration (procedures), or an AS keyword (zero-parameter procedures).
//
// declaredAnnotation is the per-object doc annotation (ViewDef.DocAnnotation /
// ProcedureDef.DocAnnotation); pass "" when not declared. When non-empty it
// is rendered after the caller-level DocPreamble (and after any
// OwnershipNotice) so callers reading the live SQL see ownership → preamble
// → per-object annotation → payload.
func applyOwnershipNoticePrefix(payload string, opts CodeObjectOptions, declaredAnnotation string) string {
	prefix := renderApplyPrefix(opts, declaredAnnotation)
	if prefix == "" {
		return payload
	}
	return prefix + payload
}

// joinSQLHeadPayload concatenates a DDL head (e.g. `CREATE VIEW ... AS`) with
// a caller-supplied body or definition. When the payload already begins with
// whitespace/newline (as option-aware comment prefixes do), it is appended
// directly so the generated SQL stays clean; otherwise a single space is
// inserted.
func joinSQLHeadPayload(head, payload string) string {
	if payload == "" {
		return head
	}
	switch payload[0] {
	case ' ', '\t', '\r', '\n':
		return head + payload
	default:
		return head + " " + payload
	}
}

// stripConfiguredApplyPrefix strips the exact configured OwnershipNotice and
// DocPreamble comment prefixes from the front of live text in their declared
// render order (notice first, then preamble), plus any leading whitespace.
// When a per-object doc annotation is declared, it is recognized in its
// natural slot (after DocPreamble, closest to the payload) and retained in
// the returned string. Configured-but-absent apply-owned markers are
// tolerated. Callers that want comment-insensitive comparison can run broader
// leading-comment normalization after this helper.
func stripConfiguredApplyPrefix(live string, opts CodeObjectOptions, declaredAnnotation string) string {
	docComment := renderOwnershipComment(opts.DocPreamble)
	annComment := renderOwnershipComment(declaredAnnotation)
	ownComment := renderOwnershipComment(opts.OwnershipNotice)

	out := strings.TrimLeft(live, " \t\r\n")
	if ownComment != "" && strings.HasPrefix(out, ownComment) {
		out = strings.TrimLeft(out[len(ownComment):], " \t\r\n")
	}
	if docComment != "" && strings.HasPrefix(out, docComment) {
		out = strings.TrimLeft(out[len(docComment):], " \t\r\n")
	}
	kept := ""
	if annComment != "" && strings.HasPrefix(out, annComment) {
		kept = annComment
		out = strings.TrimLeft(out[len(annComment):], " \t\r\n")
	}
	if kept != "" {
		return kept + " " + out
	}
	return out
}
